#include<bits/stdc++.h>
using namespace std;
int n,m,a[11][200010];
int main()
{
	scanf("%d%d",&m,&n);
	for(int i=1;i<=m;i++)
	{
		for(int j=1;j<=n;j++)
		{
			scanf("%d",&a[i][j]);
		}
	}
	if(m==2)
	{
		long long ans=0;
		for(int i=1;i<=m;i++)
		{
			for(int j=1;j<=n;j++)
			{
				ans+=1ll*a[i][j]*(n*2-1);
			}
		}
		printf("%lld\n",ans);
		return 0;
	}
	long long ans=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			int max1=-1e9,min1=1e9;
			for(int k=1;k<=m;k++)
			{
				max1=max(max1,a[k][i]+a[k][j]);
				min1=min(min1,a[k][i]+a[k][j]);
			}
			ans+=max1+min1;
		}
	}
	printf("%lld",ans);
	return 0;
}
